 1→import path from "path";
 2→import { fileURLToPath } from "url";
 3→
 4→const __dirname = path.dirname(fileURLToPath(import.meta.url));
 5→
 6→/** @type {import('next').NextConfig} */
 7→const nextConfig = {
 8→  typescript: {
 9→    ignoreBuildErrors: true,
10→  },
11→  eslint: {
12→    ignoreDuringBuilds: true,
13→  },
14→  transpilePackages: ["@compass/ui", "@compass/types", "@compass/db"],
15→  images: {
16→    remotePatterns: [
17→      {
18→        protocol: "https",
19→        hostname: "*.clerk.com",
20→      },
21→    ],
22→  },
23→  experimental: {
24→    optimizePackageImports: ["@compass/ui"],
25→    outputFileTracingRoot: path.join(__dirname, "../../"),
26→  },
27→  webpack: (config, { isServer }) => {
28→    if (isServer) {
29→      // Custom loader for Prisma's WASM query engine.
30→      // Next.js 14's bundled wasm-parser can't handle this file, so we
31→      // bypass it by treating the .wasm as JS (inlined base64 buffer →
32→      // synchronous WebAssembly.Module compilation).
33→      config.module.rules.push({
34→        test: /query_engine_bg\.wasm$/,
35→        loader: path.resolve(__dirname, "prisma-wasm-loader.js"),
36→        type: "javascript/auto",
37→      });
38→    }
39→    return config;
40→  },
41→};
42→
43→export default nextConfig;
