 1→import { redirect } from "next/navigation";
 2→import { auth, currentUser } from "@clerk/nextjs/server";
 3→import { prisma } from "@compass/db";
 4→import BottomNav from "@/components/BottomNav";
 5→
 6→export default async function StudentLayout({
 7→  children,
 8→}: {
 9→  children: React.ReactNode;
10→}) {
11→  const { userId } = await auth();
12→  if (!userId) redirect("/sign-in");
13→
14→  let student = await prisma.student.findUnique({
15→    where: { clerkId: userId },
16→  });
17→
18→  // Auto-create student record if the Clerk webhook missed it
19→  if (!student) {
20→    const user = await currentUser();
21→    if (!user) redirect("/sign-in");
22→
23→    student = await prisma.student.create({
24→      data: {
25→        clerkId: userId,
26→        email: user.emailAddresses[0]?.emailAddress ?? "",
27→        firstName: user.firstName ?? "",
28→        lastName: user.lastName ?? "",
29→      },
30→    });
31→  }
32→
33→  // Redirect to onboarding if not completed
34→  if (!student.onboardingCompleted) {
35→    redirect("/onboarding");
36→  }
37→
38→  return (
39→    <div className="min-h-screen bg-[#F2F4F7] pb-20">
40→      {/* Background gradients */}
41→      <div className="fixed inset-0 overflow-hidden pointer-events-none z-0">
42→        <div className="absolute top-[-20%] right-[-10%] w-[600px] h-[600px] rounded-full bg-blue-100/40 blur-[80px]" />
43→        <div className="absolute bottom-[20%] left-[-10%] w-[400px] h-[400px] rounded-full bg-violet-100/30 blur-[80px]" />
44→      </div>
45→
46→      <main className="relative z-10 max-w-2xl mx-auto px-4 pt-6">
47→        {children}
48→      </main>
49→
50→      <BottomNav />
51→    </div>
52→  );
53→}
