117→async function handleWeeklyNudgeSweep() {
118→  const now = new Date();
119→  const cutoff90Days = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);
120→  const cutoff48Hours = new Date(now.getTime() - 48 * 60 * 60 * 1000);
121→  const cutoff72Hours = new Date(now.getTime() - 72 * 60 * 60 * 1000);
122→
123→  // Get all students with notification preferences enabled
124→  const students = await prisma.student.findMany({
125→    where: { onboardingCompleted: true },
126→    include: {
127→      notificationPrefs: true,
128→      sessions: {
129→        orderBy: { createdAt: "desc" },
130→        take: 1,
131→        select: { completedAt: true, createdAt: true },
132→      },
133→      notifications: {
134→        where: {
135→          type: "REFLECTION_NUDGE",
136→          createdAt: { gte: cutoff48Hours },
137→        },
138→        take: 1,
139→      },
140→      signalProfiles: {
141→        orderBy: { createdAt: "desc" },
142→        take: 1,
143→        select: { compressedSummary: true },
144→      },
145→    },
146→  });
147→
148→  const weekKey = `${now.getFullYear()}-W${Math.ceil(now.getDate() / 7)}`;
149→
150→  for (const student of students) {
151→    const prefs = student.notificationPrefs;
152→    if (!prefs?.reflectionNudges) continue;
153→
154→    // Check weekly cap
155→    const weeklyCount = (await redis.get(
156→      `notif-count:${student.id}:${weekKey}`
157→    )) as number | null;
158→    if ((weeklyCount ?? 0) >= (prefs.maxPerWeek ?? 3)) continue;
159→
160→    // Check 48hr cooldown
161→    if (student.notifications.length > 0) continue;
162→
163→    // Check 72hr post-session cooldown
164→    const lastSession = student.sessions[0];
165→    if (lastSession?.completedAt) {
166→      const sessionCompletedAt = new Date(lastSession.completedAt);
167→      if (sessionCompletedAt > cutoff72Hours) continue;
168→
169→      // Only nudge if it's been more than 35 days (approaching monthly)
170→      const daysSinceSession = Math.floor(
171→        (now.getTime() - sessionCompletedAt.getTime()) / (1000 * 60 * 60 * 24)
172→      );
173→      if (daysSinceSession < 25) continue;
174→    }
175→
176→    // Check quiet hours
177→    const hour = now.getHours();
178→    const quietStart = parseInt(prefs.quietHoursStart?.split(":")[0] ?? "21");
179→    const quietEnd = parseInt(prefs.quietHoursEnd?.split(":")[0] ?? "8");
180→    const inQuietHours =
181→      quietStart > quietEnd
182→        ? hour >= quietStart || hour < quietEnd
183→        : hour >= quietStart && hour < quietEnd;
184→    if (inQuietHours) continue;
185→
186→    // Generate personalized notification
187→    try {
188→      const content = await aiService.generateNotification({
189→        studentId: student.id,
190→        triggerType: "REFLECTION_NUDGE",
191→        compressedSummary:
192→          student.signalProfiles[0]?.compressedSummary ?? undefined,
193→      });
194→
195→      await prisma.notification.create({
196→        data: {
197→          studentId: student.id,
198→          type: "REFLECTION_NUDGE",
199→          title: content.title,
200→          body: content.body,
201→        },
202→      });
203→
204→      // Increment weekly count
205→      await redis.incr(`notif-count:${student.id}:${weekKey}`);
206→      await redis.expire(
207→        `notif-count:${student.id}:${weekKey}`,
208→        60 * 60 * 24 * 7
209→      );
210→    } catch {
211→      // Log and continue
212→      console.error(`Failed to generate nudge for student ${student.id}`);
213→    }
214→  }
215→}
216→
217→async function handleOpportunitySweep() {
218→  // Find upcoming opportunities (programs with deadlines within 3 weeks)
219→  const threeWeeksOut = new Date();
220→  threeWeeksOut.setDate(threeWeeksOut.getDate() + 21);
221→
222→  // Get all students with signal profiles
223→  const students = await prisma.student.findMany({
224→    where: { onboardingCompleted: true },
225→    include: {
226→      signalProfiles: {
227→        orderBy: { createdAt: "desc" },
228→        take: 1,
229→        select: { compressedSummary: true, interestClusters: true },
230→      },
231→      notificationPrefs: true,
232→    },
233→    take: 100,
234→  });
235→
236→  // For each student with a profile, generate an opportunity notification
237→  for (const student of students) {
238→    const prefs = student.notificationPrefs;
239→    if (!prefs?.opportunityAlerts) continue;
240→
241→    const profile = student.signalProfiles[0];
242→    if (!profile?.compressedSummary) continue;
243→
244→    // Check weekly cap
245→    const now = new Date();
246→    const weekKey = `${now.getFullYear()}-W${Math.ceil(now.getDate() / 7)}`;
247→    const weeklyCount = (await redis.get(
248→      `notif-count:${student.id}:${weekKey}`
249→    )) as number | null;
250→    if ((weeklyCount ?? 0) >= (prefs.maxPerWeek ?? 3)) continue;
251→
252→    // Check for recent opportunity notification (7 days cooldown)
253→    const recentOpportunity = await prisma.notification.findFirst({
254→      where: {
255→        studentId: student.id,
256→        type: "OPPORTUNITY",
257→        createdAt: {
258→          gte: new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000),
259→        },
260→      },
261→    });
262→    if (recentOpportunity) continue;
263→
264→    try {
265→      const content = await aiService.generateNotification({
266→        studentId: student.id,
267→        triggerType: "OPPORTUNITY",
268→        compressedSummary: profile.compressedSummary,
269→      });
270→
271→      await prisma.notification.create({
272→        data: {
273→          studentId: student.id,
274→          type: "OPPORTUNITY",
275→          title: content.title,
276→          body: content.body,
277→        },
278→      });
279→
280→      await redis.incr(`notif-count:${student.id}:${weekKey}`);
281→      await redis.expire(`notif-count:${student.id}:${weekKey}`, 60 * 60 * 24 * 7);
282→    } catch {
283→      console.error(`Failed opportunity sweep for student ${student.id}`);
284→    }
285→  }
286→}
287→
288→export const POST = verifySignatureAppRouter(handler);
