 7→export default async function ReflectPage() {
 8→  const student = await requireStudent();
 9→
10→  const now = new Date();
11→  const monthKey = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}`;
12→
13→  // Check for existing session this month
14→  const existingSession = await prisma.reflectionSession.findFirst({
15→    where: { studentId: student.id, monthKey },
16→  });
17→
18→  if (existingSession && !existingSession.completedAt) {
19→    // Resume in-progress session
20→    redirect(`/reflect/${existingSession.id}`);
21→  }
22→
23→  if (existingSession?.completedAt) {
24→    // Already completed this month
25→    return (
26→      <div className="min-h-[60vh] flex items-center justify-center">
27→        <div className="glass-card p-8 text-center max-w-sm">
28→          <div className="text-5xl mb-4">✓</div>
29→          <h2 className="text-xl font-bold text-[#1A1A2E] mb-2">
30→            All caught up for {now.toLocaleString("default", { month: "long" })}
31→          </h2>
32→          <p className="text-[#6B7280] text-sm mb-6">
33→            Your monthly reflection is complete. Come back next month to continue building your signal profile.
34→          </p>
35→          <Link href="/" className="btn-primary">
36→            Back to Home
37→          </Link>
38→        </div>
39→      </div>
40→    );
41→  }
42→
43→  return (
44→    <div className="min-h-[60vh] flex items-center justify-center">
45→      <div className="glass-card p-8 text-center max-w-sm">
46→        <div className="text-5xl mb-4">🧭</div>
47→        <h2 className="text-xl font-bold text-[#1A1A2E] mb-2">
48→          {now.toLocaleString("default", { month: "long" })} Reflection
49→        </h2>
50→        <p className="text-[#6B7280] text-sm mb-6">
51→          10–15 minutes to capture what&apos;s been on your mind, what you&apos;ve been doing, and what&apos;s curious to you.
52→        </p>
53→        <StartSessionButton studentId={student.id} monthKey={monthKey} />
54→      </div>
55→    </div>
56→  );
57→}
