 1→import { requireStudent } from "@/lib/auth";
 2→import { prisma } from "@compass/db";
 3→import { notFound, redirect } from "next/navigation";
 4→import SessionWizard from "@/components/session/SessionWizard";
 5→
 6→export default async function SessionPage({
 7→  params,
 8→}: {
 9→  params: Promise<{ sessionId: string }>;
10→}) {
11→  const student = await requireStudent();
12→  const { sessionId } = await params;
13→
14→  const session = await prisma.reflectionSession.findFirst({
15→    where: { id: sessionId, studentId: student.id },
16→    include: {
17→      activities: { orderBy: { createdAt: "asc" } },
18→      reflections: { orderBy: { createdAt: "asc" } },
19→    },
20→  });
21→
22→  if (!session) notFound();
23→
24→  // Redirect if already completed
25→  if (session.completedAt) {
26→    redirect(`/reflect/${sessionId}/complete`);
27→  }
28→
29→  // Get existing student activities (for suggestions)
30→  const allActivities = await prisma.activity.findMany({
31→    where: { studentId: student.id, isOngoing: true },
32→    orderBy: { createdAt: "desc" },
33→    take: 20,
34→  });
35→
36→  return (
37→    <SessionWizard
38→      session={session}
39→      student={student}
40→      allActivities={allActivities}
41→    />
42→  );
43→}
