 1→import { NextResponse } from "next/server";
 2→import { requireStudent } from "@/lib/auth";
 3→import { prisma } from "@compass/db";
 4→import { z } from "zod";
 5→
 6→const updateSchema = z.object({
 7→  responseText: z.string().optional(),
 8→  isSharedWithCounselor: z.boolean().optional(),
 9→});
10→
11→export async function PATCH(
12→  req: Request,
13→  { params }: { params: Promise<{ id: string }> }
14→) {
15→  try {
16→    const student = await requireStudent();
17→    const { id } = await params;
18→    const body = await req.json();
19→    const data = updateSchema.parse(body);
20→
21→    const wordCount =
22→      data.responseText !== undefined
23→        ? data.responseText.trim().split(/\s+/).filter(Boolean).length
24→        : undefined;
25→
26→    const result = await prisma.reflection.updateMany({
27→      where: { id, studentId: student.id },
28→      data: {
29→        ...data,
30→        ...(wordCount !== undefined ? { wordCount } : {}),
31→      },
32→    });
33→
34→    if (result.count === 0) {
35→      return NextResponse.json({ error: "Not found" }, { status: 404 });
36→    }
37→
38→    return NextResponse.json({ success: true });
39→  } catch (error) {
40→    const message = error instanceof Error ? error.message : "Unknown error";
41→    return NextResponse.json({ error: message }, { status: 400 });
42→  }
