 1→import { NextResponse } from "next/server";
 2→import { requireCounselor } from "@/lib/auth";
 3→import { prisma } from "@compass/db";
 4→
 5→export async function GET() {
 6→  try {
 7→    const counselor = await requireCounselor();
 8→
 9→    const students = await prisma.student.findMany({
10→      where: { schoolId: counselor.schoolId },
11→      include: {
12→        signalProfiles: {
13→          orderBy: { createdAt: "desc" },
14→          take: 1,
15→        },
16→        sessions: {
17→          orderBy: { createdAt: "desc" },
18→          take: 1,
19→          select: {
20→            id: true,
21→            completedAt: true,
22→            createdAt: true,
23→          },
24→        },
25→        privacySettings: true,
26→      },
27→      orderBy: { lastName: "asc" },
28→    });
29→
30→    const now = new Date();
31→
32→    const result = students.map((student) => {
33→      const latestProfile = student.signalProfiles[0];
34→      const lastSession = student.sessions[0];
35→
36→      // Calculate engagement status
37→      let engagementStatus: "active" | "warning" | "inactive" = "inactive";
38→      if (lastSession?.completedAt) {
39→        const daysSince = Math.floor(
40→          (now.getTime() - new Date(lastSession.completedAt).getTime()) /
41→            (1000 * 60 * 60 * 24)
42→        );
43→        if (daysSince <= 45) engagementStatus = "active";
44→        else if (daysSince <= 90) engagementStatus = "warning";
45→      }
46→
47→      // Only expose privacy-allowed data
48→      const privacy = student.privacySettings;
49→      const clusters = latestProfile?.interestClusters;
50→
51→      return {
52→        id: student.id,
53→        firstName: student.firstName,
54→        lastName: student.lastName,
55→        gradeLevel: student.gradeLevel,
56→        email: student.email,
57→        onboardingCompleted: student.onboardingCompleted,
58→        lastSessionDate: lastSession?.completedAt,
59→        engagementStatus,
60→        breadthScore:
61→          privacy?.shareBreadthScore !== false
62→            ? latestProfile?.breadthScore
63→            : null,
64→        topInterests:
65→          privacy?.shareInterestClusters !== false && Array.isArray(clusters)
66→            ? (clusters as Array<{ label: string }>)
67→                .slice(0, 2)
68→                .map((c) => c.label)
69→            : null,
70→        hasSignalProfile: !!latestProfile,
71→      };
72→    });
73→
74→    return NextResponse.json(result);
75→  } catch (error) {
76→    const message = error instanceof Error ? error.message : "Unknown error";
77→    return NextResponse.json({ error: message }, { status: 400 });
78→  }
79→}
