188→                          className="text-[10px] px-2 py-0.5 bg-blue-50 text-blue-700 rounded-full"
189→                        >
190→                          {interest}
191→                        </span>
192→                      ))}
193→                    </div>
194→                  ) : (
195→                    <span className="text-xs text-[#9CA3AF]">Private</span>
196→                  )}
197→                </td>
198→                <td className="px-4 py-4">
199→                  {student.breadthScore !== null ? (
200→                    <div className="flex items-center gap-2">
201→                      <div className="w-16 h-1.5 bg-gray-200 rounded-full overflow-hidden">
202→                        <div
203→                          className="h-full bg-[#3B82F6] rounded-full"
204→                          style={{ width: `${student.breadthScore}%` }}
205→                        />
206→                      </div>
207→                      <span className="text-xs text-[#6B7280]">
208→                        {Math.round(student.breadthScore)}
209→                      </span>
210→                    </div>
211→                  ) : (
212→                    <span className="text-xs text-[#9CA3AF]">—</span>
213→                  )}
214→                </td>
215→                <td className="px-4 py-4">
216→                  <div className="flex items-center gap-2">
217→                    <EngagementDot status={student.engagementStatus} />
218→                    <span className="text-xs text-[#6B7280] capitalize">
219→                      {student.engagementStatus}
220→                    </span>
221→                  </div>
222→                </td>
223→                <td className="px-4 py-4">
224→                  <Link
225→                    href={`/students/${student.id}`}
226→                    className="text-xs text-[#3B82F6] font-medium hover:underline"
227→                  >
228→                    View →
229→                  </Link>
230→                </td>
231→              </tr>
232→            ))}
233→          </tbody>
234→        </table>
235→
236→        {students.length === 0 && (
237→          <div className="py-12 text-center text-[#9CA3AF] text-sm">
238→            No students found for this school.
239→          </div>
240→        )}
