13→    const wasmModule = new WebAssembly.Module(wasmBuffer);
14→    module.exports = wasmModule;
15→    module.exports.__esModule = true;
16→    module.exports.default = wasmModule;
17→  `;
18→};
19→module.exports.raw = true;
